function mergeObjects(r,o){for(var n in o)o.hasOwnProperty(n)&&(r[n]=o[n]);return r}function getOrInitObject(r,o){var n=r[o];return n||(r[o]={})}function parseJSON(r){try{return JSON.parse(r)}catch(r){return logError(r),null}}function logError(r){console.error?console.error(r):console.log&&console.log("ERROR: ",r)}function varargConstructor(r,o){return new(r.bind.apply(r,[r].concat(o)))}export{mergeObjects,getOrInitObject,parseJSON,logError,varargConstructor};